from marshmallow import Schema, fields, validates, ValidationError
import traceback

class Bar(Schema):
    value = fields.String()
    @validates('value')
    def validate_value(self, value):
        if value == 'invalid':
            raise ValidationError('value cannot be invalid')

class Foo(Schema):
    bar = fields.Nested(Bar)

class FooMany(Schema):
    bars = fields.Nested(Bar, many=True)

class FooSchemaMany(Schema):
    bar = fields.Nested(Bar)
    class Meta:
        many = True

def test_case(description, schema, data, expect_error=True):
    print(f'\n{description}')
    try:
        errors = schema.validate(data)
        print('Errors:', errors)
        if expect_error:
            assert errors, 'Expected errors but got none'
        else:
            assert not errors, f'Unexpected errors: {errors}'
    except TypeError as e:
        print('ERROR: TypeError raised:', e)
        traceback.print_exc()
        raise

# Original bug
test_case('Original bug: nested field invalid type', Foo(), {'bar': 'invalid'})
test_case('Nested field valid data with validator', Foo(), {'bar': {'value': 'invalid'}})
test_case('Nested field valid data', Foo(), {'bar': {'value': 'valid'}}, expect_error=False)

# Many nested
test_case('Many nested invalid type', FooMany(), {'bars': 'invalid'})
test_case('Many nested list with invalid item', FooMany(), {'bars': [{'value': 'invalid'}]})
test_case('Many nested list with valid item', FooMany(), {'bars': [{'value': 'valid'}]}, expect_error=False)

# Schema many (top-level many)
sch_many = FooSchemaMany()
test_case('Schema many with invalid nested type', sch_many, [{'bar': 'invalid'}])
test_case('Schema many with valid nested data', sch_many, [{'bar': {'value': 'valid'}}], expect_error=False)

# Nested with field validator on parent schema (validates on parent field)
class Parent(Schema):
    bar = fields.Nested(Bar)
    @validates('bar')
    def validate_bar(self, value):
        # value is dict after nested deserialization
        if value.get('value') == 'forbidden':
